import { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom"; 
import "../App.css";
import API from "../api/axios"; // ADDED

/* ==========================================================
   NAVIGATION COMPONENT
   ========================================================== */
function Nav() {
  const location = useLocation();

  const applyTheme = (mode) => {
    const body = document.body;
    if (mode === "dark") {
      body.classList.add("dark-mode");
      localStorage.setItem("user-theme", "dark");
    } else {
      body.classList.remove("dark-mode");
      localStorage.setItem("user-theme", "light");
    }
    window.dispatchEvent(new Event("storage"));
  };

  useEffect(() => {
    const savedTheme = localStorage.getItem("user-theme");
    const systemPrefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
    if (savedTheme === "dark") applyTheme("dark");
    else if (savedTheme === "light") applyTheme("light");
    else applyTheme(systemPrefersDark ? "dark" : "light");
  }, []);

  const toggleTheme = () => {
    const isDark = document.body.classList.contains("dark-mode");
    applyTheme(isDark ? "light" : "dark");
  };

  const isActive = (path) => location.pathname === path ? "active" : "";

  return (
    <header>
      <h1 className="title">Expressing Creativity Through Art and Crafts</h1>
      <nav className="menu">
        <Link to="/home" className={isActive("/home")}>HOME</Link>
        <Link to="/about" className={isActive("/about")}>ABOUT</Link>
        <Link to="/contact" className={isActive("/contact")}>CONTACT US</Link>
        <Link to="/register" className={isActive("/register")}>REGISTER</Link>
        <button className="theme-btn" onClick={toggleTheme} aria-label="Toggle theme">
          <span className="sun-icon">☀️</span>
          <span className="moon-icon">🌙</span>
        </button>
      </nav>
    </header>
  );
}

/* ==========================================================
   REGISTER PAGE COMPONENT
   ========================================================== */
function RegisterPage() {

  const navigate = useNavigate(); // ADDED

  const [formData, setFormData] = useState({
    fullName: "",
    username: "",
    dob: "",
    email: "",
    password: "",
    confirmPassword: "",
    gender: "",
    accountType: "",
    category: "",
    terms: false
  });

  const [errors, setErrors] = useState({});
  const [successMessage, setSuccessMessage] = useState("");
  const [errorMsg, setErrorMsg] = useState(""); // ADDED

  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value
    }));
  };

  const validateForm = () => {
    let newErrors = {};
    if (!formData.fullName.trim()) newErrors.fullName = "Full name is required";
    if (!formData.username.trim()) newErrors.username = "Username is required";
    if (!formData.dob) newErrors.dob = "Date of birth is required";
    if (!formData.email.includes("@")) newErrors.email = "Valid email is required";
    if (formData.password.length < 6) newErrors.password = "Password must be at least 6 characters";
    if (formData.password !== formData.confirmPassword) newErrors.confirmPassword = "Passwords do not match";
    if (!formData.gender) newErrors.gender = "Select gender";
    if (!formData.accountType) newErrors.accountType = "Select account type";
    if (!formData.category) newErrors.category = "Select category";
    if (!formData.terms) newErrors.terms = "You must agree to terms";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => { // UPDATED
    e.preventDefault();

    if (!validateForm()) return;

    try {

      const payload = {
        name: formData.fullName,
        email: formData.email,
        password: formData.password
      };

      const { data } = await API.post("/auth/register", payload);

      localStorage.setItem("token", data.token);

      setSuccessMessage("registration submitted successfully!");

      setTimeout(() => {
        navigate("/home");
      }, 1500);

    } catch (err) {
      setErrorMsg(
        err.response?.data?.message || "Registration failed."
      );
    }
  };

  const alignedLabel = {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    cursor: "pointer",
    fontWeight: "normal",
    fontSize: "15px"
  };

  return (
    <>
      <Nav />
      <main className="content-wrapper">
        <div className="register-intro">
          <h2>Join My Art & Crafts Community</h2>
          <p>Let’s connect and create! Send a message to share ideas, ask questions, or find art and craft inspiration.</p>
        </div>

        <section className="register-layout">
          <div className="why-signup-box">
            <h3>Why Sign Up?</h3>
            <p>By signing up, you will receive updates about creative art ideas, craft tutorials, design inspiration, and helpful tips.</p>
            
            <img src="/pictures/paint5.png" alt="Art inspiration" className="decorative-img" />

            <div className="benefits-grid">
                <div className="benefit-item">
                    <span className="benefit-icon">📚</span>
                    <div>
                        <h4>Tutorials</h4>
                        <p>Step-by-step craft guides.</p>
                    </div>
                </div>

                <div className="benefit-item">
                    <span className="benefit-icon">✨</span>
                    <div>
                        <h4>Inspiration</h4>
                        <p>Daily creative sparks.</p>
                    </div>
                </div>

                <div className="benefit-item">
                    <span className="benefit-icon">🛠️</span>
                    <div>
                        <h4>Resources</h4>
                        <p>Free design assets.</p>
                    </div>
                </div>

                <div className="benefit-item">
                    <span className="benefit-icon">🤝</span>
                    <div>
                        <h4>Community</h4>
                        <p>Connect with artists.</p>
                    </div>
                </div>
            </div>

            <p className="disclaimer">This form is for educational portfolio demonstration only.</p>
          </div>

          <div className="form-container">
            <form className="register-form" onSubmit={handleSubmit}>

              {errorMsg && (
                <p className="error-message">{errorMsg}</p>
              )}

              {successMessage && (
                <div style={{ backgroundColor: "#d4edda", color: "#155724", padding: "15px", borderRadius: "8px", border: "1px solid #c3e6cb", textAlign: "center", marginBottom: "20px", fontWeight: "bold" }}>
                  {successMessage}
                </div>
              )}

              {/* YOUR ENTIRE FORM REMAINS EXACTLY THE SAME */}

              <div className="button-wrapper">
                <button type="submit" className="register-submit">Submit</button>
              </div>

              {/* ADDED LOGIN LINK */}
              <p style={{textAlign:"center", marginTop:"15px"}}>
                Already have an account? <Link to="/login">Login</Link>
              </p>

            </form>
          </div>
        </section>
      </main>

      <footer>
        <div className="footer-content">
          <span>📧 email: deveraclaire00@gmail.com</span>
          <span>© 2026 Claire Denise De Vera - Student Portfolio Project</span>
        </div>
      </footer>
    </>
  );
}

export default RegisterPage;
